import React from 'react';
import styled from 'styled-components';

const SectionTitle = styled.h4`
  font-size: 12pt;
  line-height: 12pt;
  position: relative;
  margin-bottom: .1in;
  width: 100%;
  border-bottom: solid 1px #000;

  @media (max-width: 900px) {
    font-size: 9pt;
    line-height: 9pt;
    margin-bottom: .025in;
  }
  @media (max-width: 660px) {
    font-size: 8pt;
    line-height: 8pt;
    margin-bottom: .05in;
  }
  @media print {
    font-size: 12pt;
    line-height: 12pt;
    margin-bottom: .1in;
  }
`;

const SectionContent = styled.div`
  margin: 0in 0in 0in .25in;

  ul {
    margin-bottom: 8px;
  }
  li {
    font-size: 10pt;
  }

  @media (max-width: 900px) {
    margin: 0in 0in 0in .2in;
    ul { margin-bottom: 6px; }
    li { font-size: 8pt; }
  }
  @media (max-width: 660px) {
    margin: 0in 0in 0in .125in;
    ul { margin-bottom: 4px; }
    li { font-size: 5pt; }
  }
  @media print {
    margin: 0in 0in 0in .25in;
    ul { margin-bottom: 8px; }
    li { font-size: 10pt; }
  }
`;

const TitleBar = styled.div`
  position: relative;
  height: 11pt;
  margin-bottom: .05in;
  line-height: 11pt;
  font-size: 11pt;
  font-weight: 500;

  @media (max-width: 900px) {
    height: 9pt;
    margin-bottom: .075in;
    line-height: 9pt;
    font-size: 9pt;
  }
  @media (max-width: 660px) {
    height: 6pt;
    margin-bottom: .05in;
    line-height: 6pt;
    font-size: 6pt;
  }
  @media print {
    height: 11pt;
    margin-bottom: .05in;
    line-height: 11pt;
    font-size: 11pt;
  }
`;

const JobTitle = styled.div`
  position: absolute;
`;

const DateRange = styled.div`
  position: absolute;
  right: 0;
`;

export const WorkExperience = ({ jobs }) => {
  return (
    <section>
      <SectionTitle>Work Experience</SectionTitle>
      <SectionContent>
        {jobs.map((job, index) => (
          <article key={index}>
            <TitleBar>
              <JobTitle>{job.title} - {job.company}</JobTitle>
              <DateRange>{job.dateRange}</DateRange>
            </TitleBar>
            <ul>
              {job.bullets.map((bullet, i) => (
                <li key={i}>{bullet}</li>
              ))}
            </ul>
          </article>
        ))}
      </SectionContent>
    </section>
  );
};
